const { Sequelize } = require\('sequelize'\);
const db = new Sequelize\('postgres://user:pass@localhost:5432/outline', { logging: false }\);
\(async \(\) => {
  // Get the user id to set as collaborator
  const [users] = await db.query\('SELECT id FROM users ORDER BY \\"createdAt\\" ASC LIMIT 1'\);
  const userId = users[0].id;

  // Fix all documents with null collaboratorIds
  const [result] = await db.query\(
    'UPDATE documents SET \\"collaboratorIds\\" = ARRAY[:userId]::uuid[] WHERE \\"collaboratorIds\\" IS NULL',
    { replacements: { userId } }
  \);
  console.log\('Updated documents with collaboratorIds'\);

  // Verify
  const [docs] = await db.query\('SELECT id, \\"collaboratorIds\\" FROM documents WHERE \\"deletedAt\\" IS NULL LIMIT 2'\);
  console.log\(JSON.stringify\(docs, null, 2\)\);
  await db.close\(\);
}\)\(\);
" 2>&1)

